const { db } = require('../config/database');

class AdvertisementController {
  // 创建广告投放
  static async createAdvertisement(req, res) {
    try {
      const userId = req.user.id;
      const {
        title,
        description,
        icon_url,
        lat,
        lng,
        width = 1,
        height = 1,
        start_time,
        end_time,
        repeat_count = 1
      } = req.body;

      // 验证必需字段
      if (!title || !lat || !lng || !start_time || !end_time) {
        return res.status(400).json({ error: '标题、位置、开始时间和结束时间为必填项' });
      }

      // 验证时间
      const startDate = new Date(start_time);
      const endDate = new Date(end_time);
      const now = new Date();

      if (startDate <= now) {
        return res.status(400).json({ error: '开始时间必须晚于当前时间' });
      }

      if (endDate <= startDate) {
        return res.status(400).json({ error: '结束时间必须晚于开始时间' });
      }

      // 验证尺寸
      if (width < 1 || width > 10 || height < 1 || height > 10) {
        return res.status(400).json({ error: '广告尺寸必须在1x1到10x10之间' });
      }

      // 计算网格ID
      const gridX = Math.floor((parseFloat(lng) + 180) / 0.0001);
      const gridY = Math.floor((parseFloat(lat) + 90) / 0.0001);
      const gridId = `grid_${gridX}_${gridY}`;

      // 检查该位置是否已有广告
      const existingAd = await db('advertisements')
        .where('grid_id', gridId)
        .where('status', 'active')
        .first();

      if (existingAd) {
        return res.status(400).json({ error: '该位置已有广告投放' });
      }

      // 创建广告
      const [advertisement] = await db('advertisements').insert({
        user_id: userId,
        title,
        description,
        icon_url,
        lat: parseFloat(lat),
        lng: parseFloat(lng),
        grid_id: gridId,
        width: parseInt(width),
        height: parseInt(height),
        start_time: startDate,
        end_time: endDate,
        repeat_count: parseInt(repeat_count),
        status: 'pending'
      }).returning('*');

      res.status(201).json({
        success: true,
        message: '广告投放申请已提交，等待审核',
        advertisement: {
          id: advertisement.id,
          title: advertisement.title,
          status: advertisement.status,
          start_time: advertisement.start_time,
          end_time: advertisement.end_time
        }
      });

    } catch (error) {
      console.error('创建广告失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 获取用户广告列表
  static async getUserAdvertisements(req, res) {
    try {
      const userId = req.user.id;
      const { status, limit = 20, offset = 0 } = req.query;

      let query = db('advertisements')
        .where('user_id', userId)
        .orderBy('created_at', 'desc');

      if (status) {
        query = query.where('status', status);
      }

      const advertisements = await query
        .limit(parseInt(limit))
        .offset(parseInt(offset));

      res.json({
        success: true,
        advertisements: advertisements.map(ad => ({
          id: ad.id,
          title: ad.title,
          description: ad.description,
          icon_url: ad.icon_url,
          lat: ad.lat,
          lng: ad.lng,
          width: ad.width,
          height: ad.height,
          start_time: ad.start_time,
          end_time: ad.end_time,
          status: ad.status,
          view_count: ad.view_count,
          click_count: ad.click_count,
          created_at: ad.created_at
        }))
      });

    } catch (error) {
      console.error('获取用户广告列表失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 获取活跃广告列表
  static async getActiveAdvertisements(req, res) {
    try {
      const { lat, lng, radius = 0.001 } = req.query;

      let query = db('advertisements')
        .where('status', 'active')
        .where('start_time', '<=', new Date())
        .where('end_time', '>', new Date());

      // 如果提供了位置，按距离筛选
      if (lat && lng) {
        const centerLat = parseFloat(lat);
        const centerLng = parseFloat(lng);
        
        query = query.whereRaw(`
          ST_DWithin(
            ST_MakePoint(lng, lat)::geography,
            ST_MakePoint(?, ?)::geography,
            ?
          )
        `, [centerLng, centerLat, radius * 111000]); // 转换为米
      }

      const advertisements = await query
        .orderBy('created_at', 'desc')
        .limit(100);

      res.json({
        success: true,
        advertisements: advertisements.map(ad => ({
          id: ad.id,
          title: ad.title,
          description: ad.description,
          icon_url: ad.icon_url,
          lat: ad.lat,
          lng: ad.lng,
          grid_id: ad.grid_id,
          width: ad.width,
          height: ad.height,
          view_count: ad.view_count,
          click_count: ad.click_count
        }))
      });

    } catch (error) {
      console.error('获取活跃广告失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 获取广告详情
  static async getAdvertisementDetails(req, res) {
    try {
      const { adId } = req.params;

      const advertisement = await db('advertisements as a')
        .join('users as u', 'a.user_id', 'u.id')
        .where('a.id', adId)
        .select(
          'a.*',
          'u.username as advertiser_name',
          'u.avatar_url as advertiser_avatar'
        )
        .first();

      if (!advertisement) {
        return res.status(404).json({ error: '广告不存在' });
      }

      // 增加点击次数
      await db('advertisements')
        .where('id', adId)
        .increment('click_count', 1);

      res.json({
        success: true,
        advertisement: {
          id: advertisement.id,
          title: advertisement.title,
          description: advertisement.description,
          icon_url: advertisement.icon_url,
          lat: advertisement.lat,
          lng: advertisement.lng,
          width: advertisement.width,
          height: advertisement.height,
          start_time: advertisement.start_time,
          end_time: advertisement.end_time,
          status: advertisement.status,
          view_count: advertisement.view_count,
          click_count: advertisement.click_count + 1, // 包含本次点击
          advertiser: {
            name: advertisement.advertiser_name,
            avatar: advertisement.advertiser_avatar
          }
        }
      });

    } catch (error) {
      console.error('获取广告详情失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 记录广告浏览
  static async recordAdvertisementView(req, res) {
    try {
      const { adId } = req.params;

      // 增加浏览次数
      await db('advertisements')
        .where('id', adId)
        .where('status', 'active')
        .increment('view_count', 1);

      res.json({
        success: true,
        message: '浏览记录已更新'
      });

    } catch (error) {
      console.error('记录广告浏览失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 删除广告
  static async deleteAdvertisement(req, res) {
    try {
      const userId = req.user.id;
      const { adId } = req.params;

      const advertisement = await db('advertisements')
        .where('id', adId)
        .where('user_id', userId)
        .first();

      if (!advertisement) {
        return res.status(404).json({ error: '广告不存在或无权限删除' });
      }

      // 只能删除待审核或已拒绝的广告
      if (advertisement.status === 'active') {
        return res.status(400).json({ error: '无法删除已激活的广告' });
      }

      await db('advertisements')
        .where('id', adId)
        .del();

      res.json({
        success: true,
        message: '广告删除成功'
      });

    } catch (error) {
      console.error('删除广告失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 管理员：审核广告
  static async reviewAdvertisement(req, res) {
    try {
      const { adId } = req.params;
      const { status, reject_reason } = req.body;

      if (!['approved', 'rejected'].includes(status)) {
        return res.status(400).json({ error: '无效的审核状态' });
      }

      if (status === 'rejected' && !reject_reason) {
        return res.status(400).json({ error: '拒绝时必须提供拒绝原因' });
      }

      const advertisement = await db('advertisements')
        .where('id', adId)
        .where('status', 'pending')
        .first();

      if (!advertisement) {
        return res.status(404).json({ error: '广告不存在或已审核' });
      }

      await db('advertisements')
        .where('id', adId)
        .update({
          status,
          reject_reason: status === 'rejected' ? reject_reason : null,
          updated_at: db.fn.now()
        });

      res.json({
        success: true,
        message: `广告已${status === 'approved' ? '通过' : '拒绝'}`
      });

    } catch (error) {
      console.error('审核广告失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }
}

module.exports = AdvertisementController;
